use std::thread;

fn process(n: u32) -> Result<u32, String> {
    if n == 3 {
        return Err(format!("failed on {}", n));
    }
    Ok(n * 2)
}

fn main() -> Result<(), String> {
    let handles: Vec<_> = (0u32..5)
        .map(|n| thread::spawn(move || process(n)))
        .collect();

    let results: Result<Vec<u32>, String> = handles
        .into_iter()
        .map(|h| {
            h.join()
                .map_err(|_| String::from("thread panicked"))  // handle panic
                .and_then(|r| r)  // flatten Result<Result<T,E>, E> -> Result<T,E>
        })
        .collect();

    let values = results?;
    println!("{:?}", values);
    Ok(())
}

