use anyhow::Result;
use std::thread;

fn risky_work(n: i32) -> Result<i32> {
    if n < 0 {
        return Err(anyhow::anyhow!("negative input: {}", n));
    }
    Ok(n * 2)
}

fn main() {
    let handle = thread::spawn(|| risky_work(5));
    let result = handle.join().expect("thread panicked");
    println!("{:?}", result);

    // Errors with context:
    let handle2 = thread::spawn(|| risky_work(-1));
    let err = handle2.join().expect("thread panicked").unwrap_err();
    println!("error: {}", err);
}
